import { getFontDetails } from '../../../../core/utils/get-font-details.js';
import {
  HONEYCOMB_LABEL_FONT_SIZE,
  HONEYCOMB_LABEL_FONT_WEIGHT,
  HONEYCOMB_LABEL_LINE_HEIGHT,
  HONEYCOMB_VALUE_FONT_WEIGHT,
  HONEYCOMB_VALUE_LABEL_FONT_SIZE,
  HONEYCOMB_VALUE_LINE_HEIGHT,
} from '../../../constants.js';

export const setFontDetailsToContext = (
  ctx: CanvasRenderingContext2D,
  type: 'value' | 'label',
) =>
  type === 'label'
    ? (ctx.font = getFontDetails(
        HONEYCOMB_LABEL_FONT_WEIGHT,
        HONEYCOMB_LABEL_FONT_SIZE,
        HONEYCOMB_LABEL_LINE_HEIGHT,
      ))
    : (ctx.font = getFontDetails(
        HONEYCOMB_VALUE_FONT_WEIGHT,
        HONEYCOMB_VALUE_LABEL_FONT_SIZE,
        HONEYCOMB_VALUE_LINE_HEIGHT,
      ));
